#include <stdio.h>
#include <sys/mman.h>
#include <unistd.h>
#include <string.h>
#include <signal.h>
#include <setjmp.h>

static jmp_buf jbuf;
static void segv_handler(int sig) { (void)sig; longjmp(jbuf, 1); }

int main(void) {
    long ps = sysconf(_SC_PAGESIZE);
    size_t total = (size_t)ps * 2;
    void *base = mmap(NULL, total,
        PROT_READ | PROT_WRITE,
        MAP_PRIVATE | MAP_ANONYMOUS, -1, 0);
    if (base == MAP_FAILED) { perror("mmap"); return 1; }
    char *buffer = (char *)base;
    char *guard = buffer + ps;
    ____(guard, (size_t)ps, ____);
    printf("Buffer page: OK\n");
    memset(buffer, 'A', 10);
    buffer[10] = '\0';
    printf("Buffer data: %s\n", buffer);
    signal(SIGSEGV, segv_handler);
    if (setjmp(jbuf) == 0) {
        guard[0] = 'X';
        printf("Guard write succeeded (unexpected)\n");
    } else {
        printf("Guard page caught overflow\n");
    }
    munmap(base, total);
    printf("Cleanup OK\n");
    return 0;
}

