#include <stdio.h>
#include <sys/mman.h>
#include <unistd.h>
#include <string.h>
#include <signal.h>
#include <setjmp.h>

/* == EXEMPLE: guard page simple ======================= */
void example_guard(void) {
    long ps = sysconf(_SC_PAGESIZE);
    void *p = mmap(NULL, (size_t)ps*2, PROT_READ|PROT_WRITE, MAP_PRIVATE|MAP_ANONYMOUS, -1, 0);
    mprotect((char*)p + ps, (size_t)ps, PROT_NONE);
    printf("Guard page set up at offset %ld\n", ps);
    munmap(p, (size_t)ps*2);
}

